const text = $input.item.json.message?.text || '';
const cmd = text.split(' ')[0].toLowerCase();
return [{ json: { ...$input.item.json, command: cmd } }];

const rows = $input.all();
const now = new Date();
const thisMonth = now.getMonth();
const thisYear = now.getFullYear();
const lastMonth = thisMonth === 0 ? 11 : thisMonth - 1;
const lastYear  = thisMonth === 0 ? thisYear - 1 : thisYear;

let personalThis = 0, businessThis = 0, totalLast = 0, countThis = 0;
const catTotals = {};

for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  const amt = parseFloat(r.Amount) || 0;
  if (amt <= 0) continue;
  if (d.getMonth() === thisMonth && d.getFullYear() === thisYear) {
    if (r.Type === 'Business') businessThis += amt; else personalThis += amt;
    catTotals[r.Category] = (catTotals[r.Category] || 0) + amt;
    countThis++;
  } else if (d.getMonth() === lastMonth && d.getFullYear() === lastYear) {
    totalLast += amt;
  }
}

const totalThis = personalThis + businessThis;
const monthName = now.toLocaleString('en-IN', { month: 'long', year: 'numeric' });
const lastMonthName = new Date(lastYear, lastMonth, 1).toLocaleString('en-IN', { month: 'short' });

// Month-over-month comparison (inspired by expenses.app)
let comparison = '';
if (totalLast > 0) {
  const diff = totalThis - totalLast;
  const pct = Math.round(Math.abs(diff / totalLast) * 100);
  const arrow = diff >= 0 ? '\u2191' : '\u2193';
  const sign = diff >= 0 ? '+' : '-';
  comparison = `\nvs ${lastMonthName}: ₹${totalLast.toFixed(0)} (${arrow}${pct}%)`;
}

// Top categories with mini bar
const sorted = Object.entries(catTotals).sort((a,b) => b[1]-a[1]).slice(0,5);
const catLines = sorted.map(([cat, amt]) => {
  const pct = totalThis > 0 ? Math.round((amt/totalThis)*100) : 0;
  const filled = Math.round(pct/10);
  const bar = '\u2588'.repeat(filled) + '\u2591'.repeat(10 - filled);
  return `${bar} ${cat}\n  ₹${amt.toFixed(0)} (${pct}%)`;
}).join('\n');

const msg = `\uD83D\uDCCA *${monthName} Summary*\n\n${countThis} expense(s)\n\uD83D\uDC64 Personal: ₹${personalThis.toFixed(0)}\n\uD83D\uDCBC Business: ₹${businessThis.toFixed(0)}\n\uD83D\uDCB0 Total: ₹${totalThis.toFixed(0)}${comparison}\n\n*Breakdown:*\n${catLines || '  No expenses yet'}`;
return [{ json: { message: msg } }];

const rows = $input.all();
const now = new Date();
const thisMonth = now.getMonth();
const thisYear = now.getFullYear();

const catTotals = {};
let total = 0;
for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  if (d.getMonth() !== thisMonth || d.getFullYear() !== thisYear) continue;
  const amt = parseFloat(r.Amount) || 0;
  if (amt <= 0) continue;
  const key = `${r.Category} (${r.Type})`;
  catTotals[key] = (catTotals[key] || 0) + amt;
  total += amt;
}

const sorted = Object.entries(catTotals).sort((a,b) => b[1]-a[1]);
const lines = sorted.map(([cat, amt]) => `${cat}: ₹${amt.toFixed(0)}`).join('\n');
const monthName = now.toLocaleString('en-IN', { month: 'long', year: 'numeric' });

const msg = `\uD83D\uDCCB *${monthName} Full Report*\n\n${lines || 'No expenses this month'}\n\n*Grand Total: ₹${total.toFixed(0)}*`;
return [{ json: { message: msg } }];

const rows = $input.all();
const cmdText = $('Telegram Trigger').item.json.message?.text || '';
const term = cmdText.replace('/search', '').trim().toLowerCase();
if (!term) {
  return [{ json: { message: '\uD83D\uDD0D Usage: /search keyword\nExample: /search starbucks' } }];
}
const matches = rows.map(r => r.json)
  .filter(r => r.Merchant && (
    r.Merchant.toLowerCase().includes(term) ||
    (r.Notes || '').toLowerCase().includes(term) ||
    (r.Category || '').toLowerCase().includes(term)
  ))
  .filter(r => parseFloat(r.Amount) > 0)
  .slice(-10).reverse();
if (matches.length === 0) {
  return [{ json: { message: `\uD83D\uDD0D No results for "${term}"` } }];
}
const lines = matches.map(r => `\uD83D\uDCC5 ${r.Date} | *${r.Merchant}* | ₹${parseFloat(r.Amount).toFixed(0)} | ${r.Category}`).join('\n');
return [{ json: { message: `\uD83D\uDD0D *Results for "${term}":*\n\n${lines}` } }];

const rows = $input.all();
const today = new Date().toISOString().split('T')[0];
let personal = 0, business = 0;
const items = [];
const catTotals = {};
for (const row of rows) {
  const r = row.json;
  if (r.Date !== today || !r.Amount) continue;
  const amt = parseFloat(r.Amount) || 0;
  if (amt <= 0) continue;
  if (r.Type === 'Business') business += amt; else personal += amt;
  catTotals[r.Category] = (catTotals[r.Category] || 0) + amt;
  items.push(`• *${r.Merchant}* — ₹${amt.toFixed(0)} _${r.Category}_`);
}
const total = personal + business;
if (items.length === 0) {
  return [{ json: { message: `\uD83D\uDCC5 *Today — ${today}*\n\n\u2705 No expenses yet! Still time to save \uD83D\uDE04` } }];
}
const msg = `\uD83D\uDCC5 *Today — ${today}*\n\n${items.join('\n')}\n\n\uD83D\uDC64 Personal: ₹${personal.toFixed(0)}\n\uD83D\uDCBC Business: ₹${business.toFixed(0)}\n\uD83D\uDCB0 Total: ₹${total.toFixed(0)}`;
return [{ json: { message: msg } }];

const rows = $input.all();
const cmdText = $('Telegram Trigger').item.json.message?.text || '';
const nArg = parseInt(cmdText.replace('/last', '').trim()) || 5;
const n = Math.min(Math.max(nArg, 1), 20);
const recent = rows.map(r => r.json).filter(r => r.Date && r.Amount && parseFloat(r.Amount) > 0).slice(-n).reverse();
if (recent.length === 0) {
  return [{ json: { message: '\uD83D\uDCCB No expenses found. Start logging with a photo or text!' } }];
}
const lines = recent.map((r, i) =>
  `${i+1}. *${r.Merchant}* — ₹${parseFloat(r.Amount).toFixed(0)}\n   \uD83D\uDCC2 ${r.Category} · \uD83D\uDCC5 ${r.Date}`
).join('\n\n');
const msg = `\uD83D\uDCCB *Last ${recent.length} Expense(s):*\n\n${lines}\n\n_Use /undo to remove the most recent_`;
return [{ json: { message: msg } }];

const rows = $input.all();
const now = new Date();
const dow = now.getDay();
const startOfWeek = new Date(now);
startOfWeek.setDate(now.getDate() - dow);
startOfWeek.setHours(0,0,0,0);
const weekStart = startOfWeek.toISOString().split('T')[0];

let personal = 0, business = 0, count = 0;
const catTotals = {};
const dayTotals = {};

for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  if (d < startOfWeek) continue;
  const amt = parseFloat(r.Amount) || 0;
  if (amt <= 0) continue;
  if (r.Type === 'Business') business += amt; else personal += amt;
  catTotals[r.Category] = (catTotals[r.Category] || 0) + amt;
  dayTotals[r.Date] = (dayTotals[r.Date] || 0) + amt;
  count++;
}

const total = personal + business;
const sortedCats = Object.entries(catTotals).sort((a,b) => b[1]-a[1]).slice(0,4);
const catLines = sortedCats.map(([c, a]) => `  ${c}: ₹${a.toFixed(0)}`).join('\n');

const msg = `\uD83D\uDCC5 *This Week (from ${weekStart})*\n\n${count} expense(s)\n\uD83D\uDC64 Personal: ₹${personal.toFixed(0)}\n\uD83D\uDCBC Business: ₹${business.toFixed(0)}\n\uD83D\uDCB0 Total: ₹${total.toFixed(0)}\n\n*Top Categories:*\n${catLines || '  No data'}\n\n_/summary for full month view_`;
return [{ json: { message: msg } }];

const rows = $input.all();
const now = new Date();
const cmdText = $('Telegram Trigger').item.json.message?.text || '';
const offset = parseInt(cmdText.replace('/month', '').trim()) || 0;
const target = new Date(now.getFullYear(), now.getMonth() + offset, 1);
const tMonth = target.getMonth();
const tYear  = target.getFullYear();
const pMonth = tMonth === 0 ? 11 : tMonth - 1;
const pYear  = tMonth === 0 ? tYear - 1 : tYear;

let personalT = 0, businessT = 0, totalP = 0;
const catTotals = {};

for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  const amt = parseFloat(r.Amount) || 0;
  if (amt <= 0) continue;
  if (d.getMonth() === tMonth && d.getFullYear() === tYear) {
    if (r.Type === 'Business') businessT += amt; else personalT += amt;
    catTotals[r.Category] = (catTotals[r.Category] || 0) + amt;
  } else if (d.getMonth() === pMonth && d.getFullYear() === pYear) {
    totalP += amt;
  }
}

const totalT = personalT + businessT;
const monthName = target.toLocaleString('en-IN', { month: 'long', year: 'numeric' });
const prevName  = new Date(pYear, pMonth, 1).toLocaleString('en-IN', { month: 'long', year: 'numeric' });

const diff = totalT - totalP;
const pct = totalP > 0 ? Math.round(Math.abs(diff/totalP)*100) : 0;
const trend = totalP === 0 ? '' :
  diff > 0 ? `\u2191${pct}% more than ${prevName}` :
  diff < 0 ? `\u2193${pct}% less than ${prevName}` : `same as ${prevName}`;

const sortedCats = Object.entries(catTotals).sort((a,b) => b[1]-a[1]).slice(0,5);
const catLines = sortedCats.map(([c, a]) => `  ${c}: ₹${a.toFixed(0)}`).join('\n');
const prevLine = totalP > 0 ? `\nvs ${prevName}: ₹${totalP.toFixed(0)} (${trend})` : '';

const hint = offset === 0 ? '_/month -1 for last month_' : `_/month for current month_`;
const msg = `\uD83D\uDCCA *${monthName}*\n\n\uD83D\uDC64 Personal: ₹${personalT.toFixed(0)}\n\uD83D\uDCBC Business: ₹${businessT.toFixed(0)}\n\uD83D\uDCB0 Total: ₹${totalT.toFixed(0)}${prevLine}\n\n*Top Categories:*\n${catLines || '  No data'}\n\n${hint}`;
return [{ json: { message: msg } }];

const rows = $input.all();
const dataRows = rows.map(r => r.json).filter(r => r.Date && r.Amount && parseFloat(r.Amount) > 0);
if (dataRows.length === 0) {
  return [{ json: { message: '\uD83D\uDDD1\uFE0F Nothing to undo — no expenses found.' } }];
}
const last = dataRows[dataRows.length - 1];
const sheetUrl = 'https://docs.google.com/spreadsheets/d/' + $vars.GOOGLE_SHEET_ID;
const msg = `\uD83D\uDDD1\uFE0F *Last Expense (tap to remove):*\n\n\uD83C\uDFEA *${last.Merchant}* — ₹${parseFloat(last.Amount).toFixed(0)}\n\uD83D\uDCC2 ${last.Category} · \uD83D\uDCB3 ${last.PaymentMethod || 'UPI'} · \uD83D\uDCC5 ${last.Date}\n\n[\uD83D\uDD17 Open Sheet to delete last row](${sheetUrl})\n\n_Alternatively, reply with the expense text again to re-log if removed by mistake._`;
return [{ json: { message: msg } }];
